<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Bouncing Ball Physics Playground</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body {
    min-height: 100vh;
    display: flex;
    flex-direction: column;
    align-items: center;
    justify-content: center;
    background: #111;
    color: #eee;
    font-family: system-ui, -apple-system, sans-serif;
    gap: 16px;
    padding: 20px;
  }
  h1 { font-size: 1.5rem; font-weight: 500; letter-spacing: 0.5px; }
  #sim {
    background: #1a1a1a;
    border: 1px solid #333;
    border-radius: 8px;
    box-shadow: 0 0 30px rgba(0,0,0,0.5), inset 0 0 60px rgba(0,0,0,0.3);
    cursor: crosshair;
    display: block;
  }
  .controls {
    display: flex;
    gap: 12px;
    flex-wrap: wrap;
    justify-content: center;
  }
  button {
    padding: 10px 20px;
    font-size: 0.9rem;
    font-weight: 500;
    border: none;
    border-radius: 6px;
    cursor: pointer;
    transition: all 0.15s ease;
    background: #2a2a2a;
    color: #eee;
    border: 1px solid #444;
  }
  button:hover { background: #333; border-color: #555; transform: translateY(-1px); }
  button:active { transform: translateY(0); background: #222; }
  button:focus-visible { outline: 2px solid #66aaff; outline-offset: 2px; }
  #drop { background: #2d4a2d; border-color: #3a6b3a; }
  #drop:hover { background: #355a35; }
  #play { background: #2d3d4a; border-color: #3a5a6b; }
  #play:hover { background: #354a5a; }
  #play.playing { background: #4a2d2d; border-color: #6b3a3a; }
  #play.playing:hover { background: #5a3535; }
  #clear { background: #4a2d3d; border-color: #6b3a5a; }
  #clear:hover { background: #5a354a; }
  .hint {
    font-size: 0.8rem;
    color: #777;
    text-align: center;
    max-width: 400px;
  }
</style>
</head>
<body>
<h1>Bouncing Ball Physics Playground</h1>
<canvas id="sim" width="600" height="600"></canvas>
<div class="controls">
  <button id="drop">Drop Ball</button>
  <button id="play">Pause</button>
  <button id="clear">Clear All</button>
</div>
<p class="hint">Click canvas to add balls • Gravity pulls down • Walls bounce with energy loss</p>

<script>
(() => {
  const canvas = document.getElementById('sim');
  const ctx = canvas.getContext('2d');
  const dropBtn = document.getElementById('drop');
  const playBtn = document.getElementById('play');
  const clearBtn = document.getElementById('clear');

  // Physics constants
  const GRAVITY = 0.5;
  const RESTITUTION = 0.85;
  const MIN_RADIUS = 10;
  const MAX_RADIUS = 30;

  // Simulation state
  const balls = [];
  let running = true;
  let lastTime = 0;

  // Canvas size (CSS pixels = device pixels for simplicity)
  const w = canvas.width;
  const h = canvas.height;

  // Ball class
  class Ball {
    constructor(x, y, vx = 0, vy = 0, r = null) {
      this.x = x;
      this.y = y;
      this.vx = vx;
      this.vy = vy;
      this.r = r ?? (MIN_RADIUS + Math.random() * (MAX_RADIUS - MIN_RADIUS));
      this.hue = Math.random() * 360;
    }
  }

  // Add a ball
  function addBall(x, y, vx = 0, vy = 0, r = null) {
    // Clamp to valid bounds
    const radius = r ?? (MIN_RADIUS + Math.random() * (MAX_RADIUS - MIN_RADIUS));
    const clampedX = Math.max(radius, Math.min(w - radius, x));
    const clampedY = Math.max(radius, Math.min(h - radius, y));
    balls.push(new Ball(clampedX, clampedY, vx, vy, radius));
  }

  // Clear all balls
  function clear() {
    balls.length = 0;
  }

  // Step simulation by dt (default 1 frame)
  function step(dt = 1) {
    const subSteps = Math.max(1, Math.ceil(dt / 16)); // cap sub-step size
    const subDt = dt / subSteps;

    for (let s = 0; s < subSteps; s++) {
      for (const ball of balls) {
        // Gravity
        ball.vy += GRAVITY * subDt;

        // Update position
        ball.x += ball.vx * subDt;
        ball.y += ball.vy * subDt;

        // Collision with walls - clamp and reflect
        // Left wall
        if (ball.x - ball.r < 0) {
          ball.x = ball.r;
          ball.vx = -ball.vx * RESTITUTION;
        }
        // Right wall
        if (ball.x + ball.r > w) {
          ball.x = w - ball.r;
          ball.vx = -ball.vx * RESTITUTION;
        }
        // Top wall
        if (ball.y - ball.r < 0) {
          ball.y = ball.r;
          ball.vy = -ball.vy * RESTITUTION;
        }
        // Bottom wall
        if (ball.y + ball.r > h) {
          ball.y = h - ball.r;
          ball.vy = -ball.vy * RESTITUTION;
        }
      }
    }
    draw();
  }

  // Draw all balls
  function draw() {
    // Clear with slight trail effect for satisfaction
    ctx.fillStyle = 'rgba(26, 26, 26, 0.3)';
    ctx.fillRect(0, 0, w, h);

    for (const ball of balls) {
      const gradient = ctx.createRadialGradient(
        ball.x - ball.r * 0.3, ball.y - ball.r * 0.3, ball.r * 0.1,
        ball.x, ball.y, ball.r
      );
      gradient.addColorStop(0, `hsl(${ball.hue}, 80%, 70%)`);
      gradient.addColorStop(0.5, `hsl(${ball.hue}, 70%, 55%)`);
      gradient.addColorStop(1, `hsl(${ball.hue}, 60%, 35%)`);

      ctx.beginPath();
      ctx.arc(ball.x, ball.y, ball.r, 0, Math.PI * 2);
      ctx.fillStyle = gradient;
      ctx.fill();

      // Subtle highlight
      ctx.beginPath();
      ctx.arc(ball.x - ball.r * 0.3, ball.y - ball.r * 0.3, ball.r * 0.25, 0, Math.PI * 2);
      ctx.fillStyle = 'rgba(255,255,255,0.15)';
      ctx.fill();
    }
  }

  // Animation loop
  function animate(time) {
    if (lastTime === 0) lastTime = time;
    const dt = time - lastTime;
    lastTime = time;

    if (running) {
      step(dt);
    }
    requestAnimationFrame(animate);
  }

  // Event handlers
  canvas.addEventListener('click', (e) => {
    const rect = canvas.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;
    addBall(x, y, (Math.random() - 0.5) * 8, (Math.random() - 0.5) * 4);
  });

  dropBtn.addEventListener('click', () => {
    addBall(w / 2, 50, (Math.random() - 0.5) * 4, 0);
  });

  playBtn.addEventListener('click', () => {
    running = !running;
    playBtn.textContent = running ? 'Pause' : 'Play';
    playBtn.classList.toggle('playing', !running);
    if (running) lastTime = 0; // reset time to avoid jump
  });

  clearBtn.addEventListener('click', () => {
    clear();
    draw();
  });

  // Expose API on window.sim
  window.sim = {
    get w() { return w; },
    get h() { return h; },
    balls: () => balls.map(b => ({ x: b.x, y: b.y, vx: b.vx, vy: b.vy, r: b.r })),
    addBall,
    clear,
    step
  };

  // Initial draw and start loop
  draw();
  requestAnimationFrame(animate);
})();
</script>
</body>
</html>
